/* ════════════════════════════════════════════════════════════════
   <ThwLogo /> — adaptive THW brand mark
   ────────────────────────────────────────────────────────────────
   Swaps between the LIGHT-bubble and DARK-bubble logo automatically:

   • If `customBackground` (hex) is given → picks by WCAG luminance.
   • Otherwise reads the active theme: a `dark` / `light` class on
     <html> or <body>, falling back to prefers-color-scheme, falling
     back to the brand default (dark).
   • Reacts instantly: MutationObserver on the theme class +
     matchMedia listener — no reload, no visible flash.

   Assets:
     assets/logo-light.png  → light bubble (use on light/day surfaces)
     assets/logo-dark.png   → dark bubble  (use on dark/night surfaces)

   Usage:
     <ThwLogo size={32} />
     <ThwLogo size={36} radius={9} />
     <ThwLogo size={32} customBackground="#1E40AF" />
   ════════════════════════════════════════════════════════════════ */

// WCAG relative luminance from a #rgb / #rrggbb hex string. → 0..1
function thwGetLuminance(hex) {
  if (!hex) return 0;
  let c = hex.trim().replace('#', '');
  if (c.length === 3) c = c.split('').map(function (x) { return x + x; }).join('');
  if (c.length !== 6) return 0;
  const r = parseInt(c.slice(0, 2), 16) / 255;
  const g = parseInt(c.slice(2, 4), 16) / 255;
  const b = parseInt(c.slice(4, 6), 16) / 255;
  const a = [r, g, b].map(function (v) {
    return v <= 0.03928 ? v / 12.92 : Math.pow((v + 0.055) / 1.055, 2.4);
  });
  return 0.2126 * a[0] + 0.7152 * a[1] + 0.0722 * a[2];
}

function thwResolveIsDark(customBackground) {
  // 1 — explicit custom background wins
  if (customBackground) return thwGetLuminance(customBackground) <= 0.5;

  // 2 — explicit theme class on <html> or <body>
  const html = document.documentElement;
  const body = document.body;
  if (html.classList.contains('dark') || (body && body.classList.contains('dark'))) return true;
  if (html.classList.contains('light') || (body && body.classList.contains('light'))) return false;

  // 3 — system preference
  if (window.matchMedia) return window.matchMedia('(prefers-color-scheme: dark)').matches;

  // 4 — brand default is the dark theme
  return true;
}

function ThwLogo(props) {
  const size = props.size != null ? props.size : 36;
  const radius = props.radius != null ? props.radius : Math.round(size * 0.225);
  const alt = props.alt != null ? props.alt : 'THW Coaching';
  const customBackground = props.customBackground;

  const [isDark, setIsDark] = React.useState(function () {
    return thwResolveIsDark(customBackground);
  });

  React.useEffect(function () {
    const update = function () { setIsDark(thwResolveIsDark(customBackground)); };
    update();

    // A fixed custom background never changes — no observers needed.
    if (customBackground) return undefined;

    const observer = new MutationObserver(update);
    observer.observe(document.documentElement, { attributes: true, attributeFilter: ['class'] });
    if (document.body) {
      observer.observe(document.body, { attributes: true, attributeFilter: ['class'] });
    }

    let mq = null;
    if (window.matchMedia) {
      mq = window.matchMedia('(prefers-color-scheme: dark)');
      if (mq.addEventListener) mq.addEventListener('change', update);
      else if (mq.addListener) mq.addListener(update);
    }

    return function () {
      observer.disconnect();
      if (mq) {
        if (mq.removeEventListener) mq.removeEventListener('change', update);
        else if (mq.removeListener) mq.removeListener(update);
      }
    };
  }, [customBackground]);

  const THW_LOGO_DARK = "data:image/png;base64,";
  const THW_LOGO_LIGHT = "data:image/png;base64,";
  const src = isDark ? THW_LOGO_DARK : THW_LOGO_LIGHT;

  return (
    <img
      src={src}
      alt={alt}
      width={size}
      height={size}
      className={props.className}
      style={Object.assign({
        width: size,
        height: size,
        borderRadius: radius,
        display: 'block',
        objectFit: 'contain',
      }, props.style)}
    />
  );
}

// Share across Babel script scopes.
window.ThwLogo = ThwLogo;
window.thwGetLuminance = thwGetLuminance;
